import json
import boto3

dynamodb = boto3.resource('dynamodb')

def lambda_handler(event, context):
    action = event.get('apiPath')
    parameters = event.get('parameters', [])

    if action == '/order-status':
        order_id = next((p['value'] for p in parameters if p['name'] == 'orderId'), None)
        table = dynamodb.Table('Orders')
        response = table.get_item(Key={'orderId': order_id})
        return {'statusCode': 200, 'body': json.dumps(response.get('Item', {}))}

    elif action == '/process-return':
        body = json.loads(event.get('requestBody', {}).get('content', {}).get('application/json', '{}'))
        # Process return logic
        return {'statusCode': 200, 'body': json.dumps({'returnId': 'RET-12345', 'status': 'initiated'})}

    return {'statusCode': 400, 'body': 'Invalid action'}
